import Header from './Header.js'
import { useEffect } from 'react';

function Page({ children }) {
  const pageTitle = 'harrison-e';
  useEffect(() => {
    document.title = pageTitle 
  }, []);

  return (
    <div className='w-full max-w-128 h-screen space-y-5'>
      <Header />
      <div className='grid place-content-center text-lime-100 p-6 space-y-5'>
        { children }
      </div>
    </div>
  );
}

export default Page;
